int main() {
    Dog myDog;
    Cat myCat;

    std::cout << "Direct calls:\n";
    std::cout << "Dog sound: ";
    myDog.sound();
    std::cout << "Cat sound: ";
    myCat.sound();

    std::cout << "\nPolymorphic calls (semantic error demonstration):\n";
    Animal* polyDog = new Dog();
    Animal* polyCat = new Cat();

    std::cout << "Dog via Animal* sound: ";
    polyDog->sound();
    std::cout << "Cat via Animal* sound: ";
    polyCat->sound();

    delete polyDog;
    delete polyCat;

    return 0;
}
